const inputString = $input.first().json.To_Date;
const date = new Date(inputString);

// Format the date
const formattedDate = date.toLocaleDateString('en-US');

// Return as an array of objects
return [{ 
    original_date: inputString,
    to_date: formattedDate 
}];

